import { NextRequest, NextResponse } from 'next/server';
import { createClient, isSupabaseConfigured } from '@/lib/supabase/server';

export async function GET(request: NextRequest) {
  if (!isSupabaseConfigured()) {
    return NextResponse.json([], { status: 200 });
  }
  const supabase = await createClient();
  const { searchParams } = new URL(request.url);
  const status = searchParams.get('status');
  const search = searchParams.get('search');
  const sortBy = searchParams.get('sortBy') || 'created_at';
  const sortOrder = searchParams.get('sortOrder') || 'desc';
  const serviceType = searchParams.get('serviceType');

  const sortColumn = sortBy === 'name' ? 'name' : sortBy === 'status' ? 'status' : 'created_at';
  const ascending = sortOrder === 'asc';

  let query = supabase
    .from('leads')
    .select('*')
    .order(sortColumn, { ascending });

  if (status) {
    query = query.eq('status', status);
  }
  if (serviceType) {
    query = query.eq('form_type', serviceType);
  }
  if (search) {
    query = query.or(
      `name.ilike.%${search}%,email.ilike.%${search}%,phone.ilike.%${search}%,address.ilike.%${search}%`
    );
  }

  const { data, error } = await query;

  if (error) {
    console.error('Error fetching leads:', error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
  return NextResponse.json(data);
}

export async function POST(request: NextRequest) {
  if (!isSupabaseConfigured()) {
    return NextResponse.json({ error: 'Database not configured' }, { status: 503 });
  }
  const body = await request.json();
  const { name, email, phone, address, lawnSize, formType, notes } = body;

  if (!name?.trim() || !email?.trim() || !phone?.trim()) {
    return NextResponse.json(
      { error: 'Name, email, and phone are required' },
      { status: 400 }
    );
  }

  const supabase = await createClient();
  const { data, error } = await supabase
    .from('leads')
    .insert({
      name: String(name).trim(),
      email: String(email).trim().toLowerCase(),
      phone: String(phone).trim(),
      address: address?.trim() || null,
      lawn_size: lawnSize?.trim() || null,
      form_type: formType?.trim() || 'Season pass',
      notes: notes?.trim() || null,
      form_data: {},
    })
    .select()
    .single();

  if (error) {
    console.error('Error creating lead:', error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
  return NextResponse.json(data);
}
